extra.modelCss:
/* Exemplos de seletores */

/* TAG (base) */
body {
  font-family: system-ui;
}

/* CLASS (padrão) */
.card {
  padding: 16px;
  border: 1px solid #ddd;
  border-radius: 12px;
}

/* ID (use pouco) */
#top {
  position: sticky;
  top: 0;
}

/* Combinado (p dentro do card) */
.card p {
  color: #333;
}

/* Estado */
.btn:hover {
  opacity: 0.9;
}
